/**
 * @summary List transactions
 */
export const getListTransactionsUrl = (
  businessId: number,
  params?: ListTransactionsParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/businesses/${businessId}/transactions?${stringifiedParams}`
    : `/api/businesses/${businessId}/transactions`;
};

export const listTransactions = async (
  businessId: number,
  params?: ListTransactionsParams,
  options?: RequestInit,
): Promise<TransactionListResponse> => {
  return customFetch<TransactionListResponse>(
    getListTransactionsUrl(businessId, params),
    {
      ...options,
      method: "GET",
    },
  );
};

export const getListTransactionsQueryKey = (
  businessId: number,
  params?: ListTransactionsParams,
) => {
  return [
    `/api/businesses/${businessId}/transactions`,
    ...(params ? [params] : []),
  ] as const;
};

export const getListTransactionsQueryOptions = <
  TData = Awaited<ReturnType<typeof listTransactions>>,
  TError = ErrorType<unknown>,
>(
  businessId: number,
  params?: ListTransactionsParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof listTransactions>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getListTransactionsQueryKey(businessId, params);

  const queryFn: QueryFunction<
    Awaited<ReturnType<typeof listTransactions>>
  > = ({ signal }) =>
    listTransactions(businessId, params, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!businessId,
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof listTransactions>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type ListTransactionsQueryResult = NonNullable<
  Awaited<ReturnType<typeof listTransactions>>
>;
export type ListTransactionsQueryError = ErrorType<unknown>;

/**
 * @summary List transactions
 */

export function useListTransactions<
  TData = Awaited<ReturnType<typeof listTransactions>>,
  TError = ErrorType<unknown>,
>(
  businessId: number,
  params?: ListTransactionsParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof listTransactions>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getListTransactionsQueryOptions(
    businessId,
    params,
    options,
  );

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}

