  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/businesses/${businessId}/reports/profit-loss?${stringifiedParams}`
    : `/api/businesses/${businessId}/reports/profit-loss`;
